use crate::types::{DecideInput, DecideOutput};

const LIC_COUNT: usize = 15;
const PI: f64 = 3.1415926535;

fn round_to_six_significant(value: f64) -> f64 {
    if value == 0.0 || !value.is_finite() {
        return value;
    }

    let exponent = value.abs().log10().floor() as i32;
    let scale = 10_f64.powi(5 - exponent);
    (value * scale).round() / scale
}

pub fn realcompare(a: f64, b: f64) -> &'static str {
    let rounded_a = round_to_six_significant(a);
    let rounded_b = round_to_six_significant(b);
    let tolerance = f64::EPSILON * rounded_a.abs().max(rounded_b.abs()).max(1.0) * 8.0;

    if (rounded_a - rounded_b).abs() <= tolerance {
        "EQ"
    } else if rounded_a < rounded_b {
        "LT"
    } else {
        "GT"
    }
}

fn lt(a: f64, b: f64) -> bool {
    realcompare(a, b) == "LT"
}

fn eq(a: f64, b: f64) -> bool {
    realcompare(a, b) == "EQ"
}

fn gt(a: f64, b: f64) -> bool {
    realcompare(a, b) == "GT"
}

fn ge(a: f64, b: f64) -> bool {
    let cmp = realcompare(a, b);
    cmp == "GT" || cmp == "EQ"
}

fn points_equal(x1: f64, y1: f64, x2: f64, y2: f64) -> bool {
    eq(x1, x2) && eq(y1, y2)
}

fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    (dx * dx + dy * dy).sqrt()
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    ((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1)).abs() / 2.0
}

fn angle_condition(x1: f64, y1: f64, xv: f64, yv: f64, x3: f64, y3: f64, epsilon: f64) -> bool {
    if points_equal(x1, y1, xv, yv) || points_equal(x3, y3, xv, yv) {
        return false;
    }

    let ax = x1 - xv;
    let ay = y1 - yv;
    let bx = x3 - xv;
    let by = y3 - yv;

    let mag_a = (ax * ax + ay * ay).sqrt();
    let mag_b = (bx * bx + by * by).sqrt();
    let mut cos_theta = (ax * bx + ay * by) / (mag_a * mag_b);
    if cos_theta > 1.0 {
        cos_theta = 1.0;
    } else if cos_theta < -1.0 {
        cos_theta = -1.0;
    }

    let angle = cos_theta.acos();
    lt(angle, PI - epsilon) || gt(angle, PI + epsilon)
}

fn circumcircle_radius_needed(
    x1: f64,
    y1: f64,
    x2: f64,
    y2: f64,
    x3: f64,
    y3: f64,
) -> f64 {
    let a = distance(x2, y2, x3, y3);
    let b = distance(x1, y1, x3, y3);
    let c = distance(x1, y1, x2, y2);

    let mut sides = [a, b, c];
    sides.sort_by(f64::total_cmp);

    let s0_sq = sides[0] * sides[0];
    let s1_sq = sides[1] * sides[1];
    let s2_sq = sides[2] * sides[2];

    if ge(s2_sq, s0_sq + s1_sq) {
        return sides[2] / 2.0;
    }

    let area = triangle_area(x1, y1, x2, y2, x3, y3);
    if eq(area, 0.0) {
        sides[2] / 2.0
    } else {
        (a * b * c) / (4.0 * area)
    }
}

fn quadrant(x: f64, y: f64) -> usize {
    if ge(x, 0.0) && ge(y, 0.0) {
        1
    } else if lt(x, 0.0) && ge(y, 0.0) {
        2
    } else if lt(x, 0.0) && lt(y, 0.0) {
        3
    } else {
        4
    }
}

fn lic1(input: &DecideInput) -> bool {
    let length1 = input.parameters.length1;
    (0..input.numpoints - 1).any(|i| {
        gt(
            distance(input.x[i], input.y[i], input.x[i + 1], input.y[i + 1]),
            length1,
        )
    })
}

fn lic2(input: &DecideInput) -> bool {
    let radius1 = input.parameters.radius1;
    (0..input.numpoints - 2).any(|i| {
        gt(
            circumcircle_radius_needed(
                input.x[i],
                input.y[i],
                input.x[i + 1],
                input.y[i + 1],
                input.x[i + 2],
                input.y[i + 2],
            ),
            radius1,
        )
    })
}

fn lic3(input: &DecideInput) -> bool {
    let epsilon = input.parameters.epsilon;
    (0..input.numpoints - 2).any(|i| {
        angle_condition(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
            input.x[i + 2],
            input.y[i + 2],
            epsilon,
        )
    })
}

fn lic4(input: &DecideInput) -> bool {
    let area1 = input.parameters.area1;
    (0..input.numpoints - 2).any(|i| {
        gt(
            triangle_area(
                input.x[i],
                input.y[i],
                input.x[i + 1],
                input.y[i + 1],
                input.x[i + 2],
                input.y[i + 2],
            ),
            area1,
        )
    })
}

fn lic5(input: &DecideInput) -> bool {
    let q_pts = input.parameters.q_pts;
    let quads = input.parameters.quads;

    (0..=input.numpoints - q_pts).any(|start| {
        let mut seen = [false; 4];
        for i in start..start + q_pts {
            seen[quadrant(input.x[i], input.y[i]) - 1] = true;
        }
        seen.iter().filter(|&&flag| flag).count() > quads
    })
}

fn lic6(input: &DecideInput) -> bool {
    (0..input.numpoints - 1).any(|i| lt(input.x[i + 1] - input.x[i], 0.0))
}

fn lic7(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }

    let n_pts = input.parameters.n_pts;
    let dist_limit = input.parameters.dist;

    (0..=input.numpoints - n_pts).any(|start| {
        let end = start + n_pts - 1;
        let x1 = input.x[start];
        let y1 = input.y[start];
        let x2 = input.x[end];
        let y2 = input.y[end];

        if points_equal(x1, y1, x2, y2) {
            (start + 1..end).any(|i| gt(distance(x1, y1, input.x[i], input.y[i]), dist_limit))
        } else {
            let base = distance(x1, y1, x2, y2);
            (start + 1..end).any(|i| {
                let numerator =
                    ((y2 - y1) * input.x[i] - (x2 - x1) * input.y[i] + x2 * y1 - y2 * x1).abs();
                gt(numerator / base, dist_limit)
            })
        }
    })
}

fn lic8(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }

    let k_pts = input.parameters.k_pts;
    let length1 = input.parameters.length1;

    (0..input.numpoints - k_pts - 1).any(|i| {
        let j = i + k_pts + 1;
        gt(
            distance(input.x[i], input.y[i], input.x[j], input.y[j]),
            length1,
        )
    })
}

fn lic9(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;
    let radius1 = input.parameters.radius1;

    (0..input.numpoints - a_pts - b_pts - 2).any(|i| {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;
        gt(
            circumcircle_radius_needed(
                input.x[i],
                input.y[i],
                input.x[j],
                input.y[j],
                input.x[k],
                input.y[k],
            ),
            radius1,
        )
    })
}

fn lic10(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let c_pts = input.parameters.c_pts;
    let d_pts = input.parameters.d_pts;
    let epsilon = input.parameters.epsilon;

    (0..input.numpoints - c_pts - d_pts - 2).any(|i| {
        let j = i + c_pts + 1;
        let k = j + d_pts + 1;
        angle_condition(
            input.x[i],
            input.y[i],
            input.x[j],
            input.y[j],
            input.x[k],
            input.y[k],
            epsilon,
        )
    })
}

fn lic11(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let e_pts = input.parameters.e_pts;
    let f_pts = input.parameters.f_pts;
    let area1 = input.parameters.area1;

    (0..input.numpoints - e_pts - f_pts - 2).any(|i| {
        let j = i + e_pts + 1;
        let k = j + f_pts + 1;
        gt(
            triangle_area(
                input.x[i],
                input.y[i],
                input.x[j],
                input.y[j],
                input.x[k],
                input.y[k],
            ),
            area1,
        )
    })
}

fn lic12(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }

    let g_pts = input.parameters.g_pts;

    (0..input.numpoints - g_pts - 1).any(|i| {
        let j = i + g_pts + 1;
        lt(input.x[j] - input.x[i], 0.0)
    })
}

fn lic13(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }

    let k_pts = input.parameters.k_pts;
    let length1 = input.parameters.length1;
    let length2 = input.parameters.length2;

    let mut has_greater = false;
    let mut has_less = false;

    for i in 0..input.numpoints - k_pts - 1 {
        let j = i + k_pts + 1;
        let d = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if gt(d, length1) {
            has_greater = true;
        }
        if lt(d, length2) {
            has_less = true;
        }
    }

    has_greater && has_less
}

fn lic14(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;
    let radius1 = input.parameters.radius1;
    let radius2 = input.parameters.radius2;

    let mut has_greater = false;
    let mut has_smaller_or_equal = false;

    for i in 0..input.numpoints - a_pts - b_pts - 2 {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;
        let required = circumcircle_radius_needed(
            input.x[i],
            input.y[i],
            input.x[j],
            input.y[j],
            input.x[k],
            input.y[k],
        );
        if gt(required, radius1) {
            has_greater = true;
        }
        if !gt(required, radius2) {
            has_smaller_or_equal = true;
        }
    }

    has_greater && has_smaller_or_equal
}

fn lic15(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }

    let e_pts = input.parameters.e_pts;
    let f_pts = input.parameters.f_pts;
    let area1 = input.parameters.area1;
    let area2 = input.parameters.area2;

    let mut has_greater = false;
    let mut has_less = false;

    for i in 0..input.numpoints - e_pts - f_pts - 2 {
        let j = i + e_pts + 1;
        let k = j + f_pts + 1;
        let area = triangle_area(
            input.x[i],
            input.y[i],
            input.x[j],
            input.y[j],
            input.x[k],
            input.y[k],
        );
        if gt(area, area1) {
            has_greater = true;
        }
        if lt(area, area2) {
            has_less = true;
        }
    }

    has_greater && has_less
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let cmv = vec![
        lic1(input),
        lic2(input),
        lic3(input),
        lic4(input),
        lic5(input),
        lic6(input),
        lic7(input),
        lic8(input),
        lic9(input),
        lic10(input),
        lic11(input),
        lic12(input),
        lic13(input),
        lic14(input),
        lic15(input),
    ];

    let mut pum = vec![vec![false; LIC_COUNT]; LIC_COUNT];
    for i in 0..LIC_COUNT {
        pum[i][i] = input.pum_diag[i];
    }

    for i in 0..LIC_COUNT {
        for j in i + 1..LIC_COUNT {
            let value = match input.lcm[i][j].as_str() {
                "NOTUSED" => true,
                "ANDD" => cmv[i] && cmv[j],
                "ORR" => cmv[i] || cmv[j],
                _ => false,
            };
            pum[i][j] = value;
            pum[j][i] = value;
        }
    }

    let fuv: Vec<bool> = (0..LIC_COUNT)
        .map(|i| !pum[i][i] || pum[i].iter().all(|&value| value))
        .collect();
    let launch = fuv.iter().all(|&value| value);

    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
